#include <array>
#include <cstddef>
#include <iostream>

int main()
{
    std::array<std::array<int, 4>, 3> grid{};

    for (std::size_t r{ 0 }; r < grid.size(); ++r)
        for (std::size_t c{ 0 }; c < grid[0].size(); ++c)
            std::cin >> grid[r][c];

    for (std::size_t r{ 0 }; r < grid.size(); ++r)
    {
        int rowSum{ 0 };
        for (std::size_t c{ 0 }; c < grid[0].size(); ++c)
        {
            if (c > 0)
                std::cout << ' ';
            std::cout << grid[r][c];
            rowSum += grid[r][c];
        }
        std::cout << ' ' << rowSum << '\n';
    }

    for (std::size_t c{ 0 }; c < grid[0].size(); ++c)
    {
        int colSum{ 0 };
        for (std::size_t r{ 0 }; r < grid.size(); ++r)
            colSum += grid[r][c];
        if (c > 0)
            std::cout << ' ';
        std::cout << colSum;
    }
    std::cout << '\n';

    return 0;
}

